class Node:
    def __init__(self, val, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

    @classmethod
    def from_input(cls, input_):
        values = [int(x) for x in input_.strip().split()]
        values.pop(0)
        stack = [(None, None, 0)]
        for val in values:
            node, parent, is_left = stack.pop()
            if parent is None:
                stack.append((val, None, False))
                continue
            if is_left:
                parent.left = cls(val)
            else:
                parent.right = cls(val)
            stack.append((val, parent, False))
        return values[0] if values else None

