#include <iostream>
#include <cstdio>
#include <vector>
#include <algorithm>
using namespace std;

class Node {
public:
    int val;
    Node* left;
    Node* right;

    Node(int val, Node* left = nullptr, Node* right = nullptr)
        : val(val), left(left), right(right) {}

    static Node* from_input(istream& in) {
        vector<int> values;
        string s;
        while (in >> s) values.push_back(stoi(s));
        if (values.empty()) return nullptr;
        Node* root = new Node(values[0]);
        for (int i = 1; i < values.size(); ++i) {
            Node* node = new Node(values[i]);
            if (values[i - 1] == 0) root->left = node;
            else root->right = node;
        }
        return root;
    }
};

class Solution {
public:
    int solve(Node* root) {
        if (root == nullptr) return 0;
        int max_sum = max(solve(root->left), solve(root->right));
        return max(root->val, root->val + max_sum);
    }
};

int main() {
    istream& in = cin;
    Node* root = Node::from_input(in);
    Solution solution;
    cout << solution.solve(root) << endl;
    return 0;
}
